import{_ as e}from"./chunks/Screenshot1.DBZ_Glnr.js";import{_ as r,o,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const s="/images/git-remote-guide/gitee-1.png",n="/images/git-remote-guide/gitee-2.png",l="/images/git-remote-guide/gitee-3.png",g="/images/git-remote-guide/config-page.png",d="/images/git-remote-guide/gitee-4.png",p="/images/git-remote-guide/gitee-5.png",k=JSON.parse('{"title":"快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1774602203000}'),c={name:"guide/getting-started.md"};function h(m,t,u,_,b,S){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h1><p><img src="'+e+'" alt="主界面"></p><div class="warning custom-block"><p class="custom-block-title">首次使用前请手动备份</p><p>备份你的存档和 Mod 文件夹。本软件经过初步测试，但多一道保险总没错。</p></div><h2 id="选择-git-平台" tabindex="-1">选择 Git 平台 <a class="header-anchor" href="#选择-git-平台" aria-label="Permalink to &quot;选择 Git 平台&quot;">​</a></h2><p>Sync the Spire 需要一个<strong>远程 Git 仓库</strong>来存储和共享 Mod 配置。有以下几种选择：</p><table tabindex="0"><thead><tr><th>平台</th><th>说明</th></tr></thead><tbody><tr><td><strong>Gitee</strong></td><td>国内访问快，推荐国内用户首选。单仓库限 500MB，单文件限 50MB</td></tr><tr><td><strong>GitHub</strong></td><td>全球通用，但国内部分地区访问受限</td></tr><tr><td>其他平台</td><td>GitLab、Gitea 等理论上均可，需自行测试兼容性</td></tr></tbody></table><h2 id="创建远程仓库-以-gitee-为例" tabindex="-1">创建远程仓库（以 Gitee 为例） <a class="header-anchor" href="#创建远程仓库-以-gitee-为例" aria-label="Permalink to &quot;创建远程仓库（以 Gitee 为例）&quot;">​</a></h2><ol><li><p>访问 <a href="https://gitee.com/" target="_blank" rel="noopener noreferrer">Gitee</a> 注册并登录。</p></li><li><p>点击右上角「<strong>+</strong>」→「<strong>新建仓库</strong>」</p></li></ol><p><img src="'+s+'" alt="新建仓库"></p><ol start="3"><li>填写仓库名称（如 <code>my-sts-mods</code>），选择开源或私有，点击「<strong>创建</strong>」。 <ul><li>开源仓库所有人可见，不限制协作人数</li><li>私有仓库只有被邀请的人可见，免费账号最多 5 名协作者</li></ul></li></ol><p><img src="'+n+'" alt="仓库信息"></p><ol start="4"><li>创建成功后进入仓库主页，点击「<strong>HTTPS</strong>」，复制仓库地址。</li></ol><p><img src="'+l+'" alt="复制链接"></p><details class="details custom-block"><summary>使用 GitHub？</summary><p>GitHub 整体流程类似，但认证方式需选择「<strong>HTTPS</strong>」，并在 GitHub 上创建 Personal Access Token 作为密码。具体步骤后续补充。</p></details><h2 id="配置-sync-the-spire" tabindex="-1">配置 Sync the Spire <a class="header-anchor" href="#配置-sync-the-spire" aria-label="Permalink to &quot;配置 Sync the Spire&quot;">​</a></h2><ol start="5"><li><p>打开 Sync the Spire，将刚才复制的仓库地址粘贴到输入框，填写你的昵称，认证方式选「<strong>免密</strong>」。</p></li><li><p>填写或自动配置好游戏路径和存档路径后，点击「<strong>保存并初始化</strong>」。完成时会弹出 Gitee 登录窗口，输入账号密码完成认证即可。</p></li></ol><p><img src="'+g+'" alt="配置页"></p><h2 id="邀请队友" tabindex="-1">邀请队友 <a class="header-anchor" href="#邀请队友" aria-label="Permalink to &quot;邀请队友&quot;">​</a></h2><p>推荐每位朋友各自注册 Gitee 账号，然后你在仓库里添加他们为协作者，各用各的账号，安全方便。</p><ol start="7"><li>进入仓库「<strong>管理</strong>」→ 左侧「<strong>仓库成员管理</strong>」→「<strong>添加成员</strong>」。</li></ol><p><img src="'+d+'" alt="添加成员"></p><ol start="8"><li>权限选「<strong>开发者</strong>」，将邀请链接发给朋友，朋友接受后再把<strong>仓库地址</strong>一并发给他们。</li></ol><p><img src="'+p+'" alt="协作者邀请"></p><ol start="9"><li>朋友在 Sync the Spire 里填入同样的仓库地址，认证方式同样选「<strong>免密</strong>」，初始化完成后即可同步你的 Mod 配置。</li></ol><hr><h2 id="认证方式怎么选" tabindex="-1">认证方式怎么选？ <a class="header-anchor" href="#认证方式怎么选" aria-label="Permalink to &quot;认证方式怎么选？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>免密</strong></td><td>公开仓库，或 Gitee 仓库（推送时系统会弹出登录窗口）</td></tr><tr><td><strong>HTTPS</strong></td><td>GitHub 等平台的私有仓库，填用户名和 Token</td></tr><tr><td><strong>SSH</strong></td><td>已配置 SSH 密钥的用户</td></tr></tbody></table><h2 id="游戏安装路径怎么找" tabindex="-1">游戏安装路径怎么找？ <a class="header-anchor" href="#游戏安装路径怎么找" aria-label="Permalink to &quot;游戏安装路径怎么找？&quot;">​</a></h2><p>Steam 中右键游戏 → <strong>管理</strong> → <strong>浏览本地文件</strong>。</p><h2 id="存档路径怎么找" tabindex="-1">存档路径怎么找？ <a class="header-anchor" href="#存档路径怎么找" aria-label="Permalink to &quot;存档路径怎么找？&quot;">​</a></h2><ol><li>启动游戏后按 <strong><code>~</code></strong> 键（波浪号键，通常在 Esc 下方）打开控制台</li><li>输入命令 <code>open saves</code> 并按回车</li><li>系统将直接打开存档所在的文件夹</li></ol>',31)])])}const q=r(c,[["render",h]]);export{k as __pageData,q as default};
